// 2.8.1    | 2022-10-24 - raj -  STRY0131148 - Add New Table for Tasker User in preparation for Out of Office
// 2.8.3 | 2023-05-24 |raj | STRY0140267 - Task Administrator Email 
// Script Continued Below
(function executeRule(current, previous /*null when async*/ ) {

    if (!((current.operation() == "delete" && current.is_task_administrator) ||
            current.operation() == "insert" && current.is_task_administrator ||
            current.operation() == "update" && current.is_task_administrator.changes())) {
        return;
    }

    // STRY0140267 - update the TopOU Administrators
	new OrganizationalScripts().setTopOUTaskAdministrators(current);
})(current, previous);
